import React, { useState, useEffect } from 'react';
import { Routes, Route, Link, useLocation } from 'react-router-dom';
import Navbar from '../components/Navbar';
import { adminAPI, superAdminAPI } from '../services/api';
import { toast } from 'react-toastify';

const AdminDashboard = () => {
  return (
    <div>
      <Navbar title="Admin Dashboard" />
      <div style={styles.container}>
        <Sidebar />
        <div style={styles.content}>
          <Routes>
            <Route path="/" element={<DashboardHome />} />
            <Route path="/employees" element={<ManageEmployees />} />
          </Routes>
        </div>
      </div>
    </div>
  );
};

const Sidebar = () => {
  const location = useLocation();
  
  const menuItems = [
    { path: '/admin', label: 'Dashboard', icon: '📊' },
    { path: '/admin/employees', label: 'Manage Employees', icon: '👥' },
  ];

  return (
    <div style={styles.sidebar}>
      {menuItems.map((item) => (
        <Link
          key={item.path}
          to={item.path}
          style={{
            ...styles.menuItem,
            backgroundColor: location.pathname === item.path ? '#9b59b6' : 'transparent',
            color: location.pathname === item.path ? 'white' : '#333',
          }}
        >
          <span>{item.icon}</span> {item.label}
        </Link>
      ))}
    </div>
  );
};

const DashboardHome = () => {
  const [stats, setStats] = useState({ employees: 0, company: null });

  useEffect(() => {
    loadStats();
  }, []);

  const loadStats = async () => {
    try {
      const [employeesRes, companyRes] = await Promise.all([
        adminAPI.getAllEmployees(),
        adminAPI.getMyCompany().catch(() => ({ data: null })),
      ]);
      setStats({
        employees: employeesRes.data.length,
        company: companyRes.data,
      });
    } catch (error) {
      toast.error('Failed to load statistics');
    }
  };

  return (
    <div>
      <h2 style={styles.pageTitle}>Dashboard Overview</h2>
      
      {stats.company && (
        <div style={styles.companyCard}>
          <h3>My Company</h3>
          <div style={styles.companyInfo}>
            {stats.company.logoUrl && (
              <img src={stats.company.logoUrl} alt="Company Logo" style={styles.companyLogo} />
            )}
            <div>
              <h2 style={styles.companyName}>{stats.company.name}</h2>
              <p>{stats.company.address}</p>
              <p>{stats.company.phone} | {stats.company.email}</p>
            </div>
          </div>
        </div>
      )}

      <div style={styles.statsGrid}>
        <div style={{...styles.statCard, backgroundColor: '#9b59b6'}}>
          <h3 style={styles.statNumber}>{stats.employees}</h3>
          <p>Total Employees</p>
        </div>
      </div>
    </div>
  );
};

const ManageEmployees = () => {
  const [employees, setEmployees] = useState([]);
  const [companies, setCompanies] = useState([]);
  const [myCompany, setMyCompany] = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    username: '',
    password: '',
    email: '',
    fullName: '',
    role: 'HR',
    companyId: '',
    employeeCode: '',
    department: '',
    designation: '',
    dateOfJoining: '',
    dateOfBirth: '',
    phoneNumber: '',
    address: '',
    emergencyContact: '',
    salary: '',
  });

  const roles = [
    'HR',
    'HR_MANAGER',
    'SOFTWARE_ENGINEER',
    'MANAGER',
    'GENERAL_MANAGER',
    'DEVELOPER',
  ];

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [employeesRes, companiesRes, companyRes] = await Promise.all([
        adminAPI.getAllEmployees(),
        superAdminAPI.getAllCompanies(),
        adminAPI.getMyCompany().catch(() => ({ data: null })),
      ]);
      setEmployees(employeesRes.data);
      setCompanies(companiesRes.data);
      setMyCompany(companyRes.data);
      if (companyRes.data) {
        setFormData(prev => ({ ...prev, companyId: companyRes.data.id }));
      }
    } catch (error) {
      toast.error('Failed to load data');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await adminAPI.createEmployee({
        ...formData,
        salary: parseFloat(formData.salary) || 0,
      });
      toast.success('Employee created successfully');
      setShowForm(false);
      setFormData({
        username: '',
        password: '',
        email: '',
        fullName: '',
        role: 'HR',
        companyId: myCompany?.id || '',
        employeeCode: '',
        department: '',
        designation: '',
        dateOfJoining: '',
        dateOfBirth: '',
        phoneNumber: '',
        address: '',
        emergencyContact: '',
        salary: '',
      });
      loadData();
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to create employee');
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this employee?')) return;
    try {
      await adminAPI.deleteEmployee(id);
      toast.success('Employee deleted successfully');
      loadData();
    } catch (error) {
      toast.error('Failed to delete employee');
    }
  };

  return (
    <div>
      <div style={styles.header}>
        <h2 style={styles.pageTitle}>Manage Employees</h2>
        <button style={styles.addBtn} onClick={() => setShowForm(!showForm)}>
          {showForm ? 'Cancel' : '+ Add Employee'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSubmit} style={styles.form}>
          <h3 style={styles.formSection}>Account Information</h3>
          <input
            type="text"
            placeholder="Username"
            value={formData.username}
            onChange={(e) => setFormData({ ...formData, username: e.target.value })}
            style={styles.input}
            required
          />
          <input
            type="password"
            placeholder="Password"
            value={formData.password}
            onChange={(e) => setFormData({ ...formData, password: e.target.value })}
            style={styles.input}
            required
          />
          <input
            type="email"
            placeholder="Email"
            value={formData.email}
            onChange={(e) => setFormData({ ...formData, email: e.target.value })}
            style={styles.input}
            required
          />
          <input
            type="text"
            placeholder="Full Name"
            value={formData.fullName}
            onChange={(e) => setFormData({ ...formData, fullName: e.target.value })}
            style={styles.input}
            required
          />
          <select
            value={formData.role}
            onChange={(e) => setFormData({ ...formData, role: e.target.value })}
            style={styles.input}
            required
          >
            {roles.map((role) => (
              <option key={role} value={role}>{role.replace('_', ' ')}</option>
            ))}
          </select>
          <select
            value={formData.companyId}
            onChange={(e) => setFormData({ ...formData, companyId: e.target.value })}
            style={styles.input}
            required
          >
            <option value="">Select Company</option>
            {companies.map((c) => (
              <option key={c.id} value={c.id}>{c.name}</option>
            ))}
          </select>

          <h3 style={styles.formSection}>Employment Details</h3>
          <input
            type="text"
            placeholder="Employee Code"
            value={formData.employeeCode}
            onChange={(e) => setFormData({ ...formData, employeeCode: e.target.value })}
            style={styles.input}
          />
          <input
            type="text"
            placeholder="Department"
            value={formData.department}
            onChange={(e) => setFormData({ ...formData, department: e.target.value })}
            style={styles.input}
          />
          <input
            type="text"
            placeholder="Designation"
            value={formData.designation}
            onChange={(e) => setFormData({ ...formData, designation: e.target.value })}
            style={styles.input}
          />
          <input
            type="date"
            placeholder="Date of Joining"
            value={formData.dateOfJoining}
            onChange={(e) => setFormData({ ...formData, dateOfJoining: e.target.value })}
            style={styles.input}
          />
          <input
            type="number"
            placeholder="Salary"
            value={formData.salary}
            onChange={(e) => setFormData({ ...formData, salary: e.target.value })}
            style={styles.input}
          />

          <h3 style={styles.formSection}>Personal Information</h3>
          <input
            type="date"
            placeholder="Date of Birth"
            value={formData.dateOfBirth}
            onChange={(e) => setFormData({ ...formData, dateOfBirth: e.target.value })}
            style={styles.input}
          />
          <input
            type="text"
            placeholder="Phone Number"
            value={formData.phoneNumber}
            onChange={(e) => setFormData({ ...formData, phoneNumber: e.target.value })}
            style={styles.input}
          />
          <input
            type="text"
            placeholder="Address"
            value={formData.address}
            onChange={(e) => setFormData({ ...formData, address: e.target.value })}
            style={styles.input}
          />
          <input
            type="text"
            placeholder="Emergency Contact"
            value={formData.emergencyContact}
            onChange={(e) => setFormData({ ...formData, emergencyContact: e.target.value })}
            style={styles.input}
          />

          <button type="submit" style={styles.submitBtn}>Create Employee</button>
        </form>
      )}

      <table style={styles.table}>
        <thead>
          <tr>
            <th style={styles.th}>ID</th>
            <th style={styles.th}>Name</th>
            <th style={styles.th}>Username</th>
            <th style={styles.th}>Role</th>
            <th style={styles.th}>Company</th>
            <th style={styles.th}>Department</th>
            <th style={styles.th}>Designation</th>
            <th style={styles.th}>Actions</th>
          </tr>
        </thead>
        <tbody>
          {employees.map((emp) => (
            <tr key={emp.id}>
              <td style={styles.td}>{emp.id}</td>
              <td style={styles.td}>{emp.fullName}</td>
              <td style={styles.td}>{emp.username}</td>
              <td style={styles.td}>{emp.role?.replace('_', ' ')}</td>
              <td style={styles.td}>{emp.companyName || '-'}</td>
              <td style={styles.td}>{emp.department || '-'}</td>
              <td style={styles.td}>{emp.designation || '-'}</td>
              <td style={styles.td}>
                <button style={styles.deleteBtn} onClick={() => handleDelete(emp.id)}>
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

